const amqplib = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'payment_events';

async function processPaymentEvent(message) {
  const event = JSON.parse(message.content.toString('utf8'));

  if (!event || typeof event !== 'object') {
    throw new Error('Invalid payment event');
  }

  const { paymentId, amount, currency, userId, action } = event;

  if (!paymentId || typeof amount !== 'number' || !currency || !userId) {
    throw new Error('Missing required payment fields');
  }

  switch (action) {
    case 'authorize':
      console.log(`Authorizing payment ${paymentId} for user ${userId}: ${amount} ${currency}`);
      break;
    case 'capture':
      console.log(`Capturing payment ${paymentId} for user ${userId}: ${amount} ${currency}`);
      break;
    case 'refund':
      console.log(`Refunding payment ${paymentId} for user ${userId}: ${amount} ${currency}`);
      break;
    default:
      console.log(`Processing payment ${paymentId} for user ${userId}: ${amount} ${currency}`);
  }
}

async function startConsumer() {
  const connection = await amqplib.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, { durable: true });
  channel.prefetch(10);

  console.log(`Waiting for messages in ${QUEUE_NAME}...`);

  channel.consume(
    QUEUE_NAME,
    async (msg) => {
      if (!msg) return;

      try {
        await processPaymentEvent(msg);
        channel.ack(msg);
      } catch (err) {
        console.error('Failed to process payment event:', err);
        channel.nack(msg, false, false);
      }
    },
    { noAck: false }
  );

  const shutdown = async () => {
    try {
      await channel.close();
      await connection.close();
    } finally {
      process.exit(0);
    }
  };

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);
}

startConsumer().catch((err) => {
  console.error('Consumer startup failed:', err);
  process.exit(1);
});